195	        observationType: eventRow.observationType,
196	        title: eventRow.title,
197	        content: eventRow.content,
198	        occurredAt: eventRow.occurredAt,
199	        significanceScore: eventRow.significanceScore ?? significanceScore ?? 0,
200	      });
201	
202	      const { object } = await generateObject({
203	        model: gateway(TRIAGE_MODEL),
204	        schema: TriageDecisionSchema,
