217	          log.warn("triage selected unknown skill, degrading to skip", {
218	            clerkOrgId,
219	            eventExternalId,
220	            selected: object.skillName,
221	          });
222	          return {
223	            decision: "skip" as const,
224	            skillName: undefined,
225	            reasoning: `selected unknown skill "${object.skillName}"; degraded to skip`,
226	          };
227	        }
228	      }
229	      return object;
230	    });
231	
232	    // ─── Step 5: emit decision ─────────────────────────────────────────
233	    await step.sendEvent("emit-agent-decided", {
234	      name: "platform/agent.decided" as const,
235	      data: {
236	        clerkOrgId,
237	        eventExternalId,
238	        decision: decision.decision,
239	        skillName: decision.skillName,
240	        reasoning: decision.reasoning,
241	        correlationId,
242	      },
243	    });
244	
245	    log.info("agent triage decided", {
246	      clerkOrgId,
247	      eventExternalId,
248	      sourceType,
249	      decision: decision.decision,

