import { neon, neonConfig } from "@neondatabase/serverless";

neonConfig.fetchEndpoint = (host: string) => `https://${host}/sql`;

const sql = neon(
  `postgresql://${process.env.DATABASE_USERNAME}:${process.env.DATABASE_PASSWORD}@${process.env.DATABASE_HOST}/postgres?sslmode=require`
);

const target = process.argv[2];
if (!target) {
  console.error("usage: tsx repoint.ts <repo-full-name>");
  process.exit(1);
}

const result = await sql`
  UPDATE lightfast_org_repo_indexes
  SET repo_full_name = ${target}
  WHERE clerk_org_id = 'REDACTED'
    AND is_active = true
  RETURNING clerk_org_id, repo_full_name
`;

console.log(JSON.stringify(result, null, 2));

